-- ----------------------------
-- Table structure for collection_runs
-- ----------------------------
DROP TABLE IF EXISTS `collection_runs`;
CREATE TABLE `collection_runs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '采集批次ID',
  `platform_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '平台编码，如 ev_station_pluz',
  `run_label` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '批次标签，格式：{platform}_{YYYYMMDD_HHMM}_{mode}',
  `mode` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'full' COMMENT '采集模式：full=全量采集，refresh=刷新采集',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'running' COMMENT '批次状态：running=进行中，completed=已完成',
  `total_stations` int unsigned DEFAULT NULL COMMENT '目标站点总数',
  `collected_count` int unsigned NOT NULL DEFAULT '0' COMMENT '已成功采集并提交的站点数',
  `started_at` datetime NOT NULL COMMENT '批次开始时间',
  `completed_at` datetime DEFAULT NULL COMMENT '批次完成时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_collection_runs_label` (`run_label`) USING BTREE,
  KEY `idx_collection_runs_platform_status_started` (`platform_code`,`status`,`started_at`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='采集批次表';

