-- Records of collection_runs
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for connector_status_snapshots
-- ----------------------------
DROP TABLE IF EXISTS `connector_status_snapshots`;
CREATE TABLE `connector_status_snapshots` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '枪口状态快照ID',
  `run_id` bigint unsigned NOT NULL COMMENT '采集批次ID，关联 collection_runs.id',
  `station_id` bigint unsigned NOT NULL COMMENT '站点ID，关联 station_sites.id',
  `platform_unit_id` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '平台侧充电桩ID，如 Charger ID',
  `unit_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '充电桩名称，如 TS (133A Max Current)',
  `connector_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '枪口位置/名称，如 ซ้าย-A、ขวา-B',
  `connector_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '枪口类型，如 DC CCS COMBO 2、AC Type 2',
  `power_text` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '功率原始文本，如 Max 120 kW',
  `power_kw` decimal(8,2) DEFAULT NULL COMMENT '功率数值，单位 kW',
  `day_price_text` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `day_price_per_kwh` decimal(10,4) DEFAULT NULL,
  `night_price_text` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `night_price_per_kwh` decimal(10,4) DEFAULT NULL,
  `status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '枪口状态，如 Available、Occupied、Closed',
  `time_period` enum('day','night') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '采集时段：day=白天，night=夜间',
  `raw_data` json DEFAULT NULL COMMENT '枪口原始采集数据JSON，包含充电桩和枪口信息',
  `collected_at` datetime NOT NULL COMMENT '快照采集时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_css_run_station` (`run_id`,`station_id`) USING BTREE,
  KEY `idx_css_station_collected` (`station_id`,`collected_at`) USING BTREE,
  KEY `idx_css_unit_connector` (`platform_unit_id`,`connector_name`) USING BTREE,
  KEY `idx_css_status_period` (`status`,`time_period`) USING BTREE,
  KEY `idx_css_price_power` (`day_price_per_kwh`,`power_kw`) USING BTREE,
  CONSTRAINT `fk_css_run` FOREIGN KEY (`run_id`) REFERENCES `collection_runs` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_css_station` FOREIGN KEY (`station_id`) REFERENCES `station_sites` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=2013 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='枪口状态快照表，包含充电桩信息';

-- ----------------------------
-- Records of connector_status_snapshots
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for station_sites
-- ----------------------------
DROP TABLE IF EXISTS `station_sites`;
CREATE TABLE `station_sites` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '站点ID',
  `platform_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '平台编码，如 ev_station_pluz',
  `station_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '站点名称',
  `brief_address` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '简略地址，来自站点列表页',
  `address` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '完整地址，来自详情页 More information',
  `overall_status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '站点整体状态，如 Available、Closed',
  `remarks` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '站点备注',
  `hours_text` json DEFAULT NULL COMMENT '营业时间JSON，按星期存储',
  `latitude` decimal(10,7) DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(10,7) DEFAULT NULL COMMENT '经度',
  `google_url` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Google Maps 分享链接',
  `collection_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending' COMMENT '采集状态：pending=待采集，completed=已完成',
  `raw_data` json DEFAULT NULL COMMENT '站点原始采集数据JSON',
  `last_collected_at` datetime DEFAULT NULL COMMENT '最近一次采集完成时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_station_platform_name` (`platform_code`,`station_name`) USING BTREE,
  KEY `idx_station_platform_status` (`platform_code`,`collection_status`) USING BTREE,
  KEY `idx_station_lat_lng` (`latitude`,`longitude`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=2507 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='充电站点表';

-- ----------------------------
-- Records of station_sites
-- ----------------------------
BEGIN;
COMMIT;

SET FOREIGN_KEY_CHECKS = 1;
